async (params, browser) => {
  // Create a new spreadsheet
  await browser.open('https://docs.google.com/spreadsheets/create')

  // Wait for new spreadsheet to fully load
  await browser.waitForSelector('table.waffle, .waffle', 25000)

  // Let the new spreadsheet initialize completely
  await browser.wait(4000)

  // Rename spreadsheet if title provided
  const create_result = await browser.evaluate(`const title = params.title; if (title) { let titleInput = document.querySelector('.docs-title-input, input.docs-title-input'); if (!titleInput) { const titleBar = document.querySelector('.docs-titlebar-text'); if (titleBar) { titleBar.click(); await new Promise(r => setTimeout(r, 500)); titleInput = document.querySelector('.docs-title-input, input.docs-title-input'); } } if (titleInput) { titleInput.focus(); titleInput.click(); await new Promise(r => setTimeout(r, 500)); titleInput.select(); await new Promise(r => setTimeout(r, 300)); document.execCommand('insertText', false, title); await new Promise(r => setTimeout(r, 300)); titleInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter', keyCode: 13, code: 'Enter', bubbles: true })); await new Promise(r => setTimeout(r, 1500)); } } const finalTitle = document.querySelector('.docs-title-input, input.docs-title-input'); const displayTitle = finalTitle ? (finalTitle.value || finalTitle.textContent || '').trim() : document.title.replace(/ - Google Sheets$/, '').trim(); return { success: true, title: displayTitle, url: window.location.href, spreadsheet_id: window.location.href.match(/\/d\/([a-zA-Z0-9_-]+)/)?.[1] || '' }`)

  return create_result
}
